import { execute, newId, nowIso, query } from "../database";

export type EmbeddingKind = "fact" | "summary" | "message" | "lore";

export interface StoredEmbedding {
  id: string;
  /** Null for chat-agnostic rows (kind 'lore'). */
  chatId: string | null;
  kind: EmbeddingKind;
  refId: string;
  /** The exact text that was embedded — compared against the current
   * source text to detect stale rows needing re-embedding. */
  text: string;
  model: string;
  dims: number;
  /** base64-encoded little-endian f32 array (see memory/vector.ts). */
  vector: string;
  createdAt: string;
}

interface EmbeddingRow {
  id: string;
  chat_id: string | null;
  kind: EmbeddingKind;
  ref_id: string;
  text: string;
  model: string;
  dims: number;
  vector: string;
  created_at: string;
}

function toEmbedding(row: EmbeddingRow): StoredEmbedding {
  return {
    id: row.id,
    chatId: row.chat_id,
    kind: row.kind,
    refId: row.ref_id,
    text: row.text,
    model: row.model,
    dims: row.dims,
    vector: row.vector,
    createdAt: row.created_at,
  };
}

export async function listEmbeddings(
  chatId: string,
  kind: EmbeddingKind,
): Promise<StoredEmbedding[]> {
  const rows = await query<EmbeddingRow>(
    "SELECT * FROM embeddings WHERE chat_id = $1 AND kind = $2",
    [chatId, kind],
  );
  return rows.map(toEmbedding);
}

export async function upsertEmbedding(
  chatId: string | null,
  kind: EmbeddingKind,
  refId: string,
  text: string,
  model: string,
  dims: number,
  vector: string,
): Promise<void> {
  await execute(
    `INSERT INTO embeddings (id, chat_id, kind, ref_id, text, model, dims, vector, created_at)
     VALUES ($1, $2, $3, $4, $5, $6, $7, $8, $9)
     ON CONFLICT (kind, ref_id)
     DO UPDATE SET text = $5, model = $6, dims = $7, vector = $8`,
    [newId(), chatId, kind, refId, text, model, dims, vector, nowIso()],
  );
}

/** Removes rows whose source (fact/message/…) no longer exists. */
export async function deleteEmbeddingsByRefIds(
  kind: EmbeddingKind,
  refIds: string[],
): Promise<void> {
  for (const refId of refIds) {
    await execute("DELETE FROM embeddings WHERE kind = $1 AND ref_id = $2", [kind, refId]);
  }
}

/** Fetches rows for a specific set of source ids (used for lorebook
 * entries, which aren't chat-scoped). Chunked to stay under SQLite's
 * parameter limit. */
export async function listEmbeddingsByRefIds(
  kind: EmbeddingKind,
  refIds: string[],
): Promise<StoredEmbedding[]> {
  const out: StoredEmbedding[] = [];
  const CHUNK = 200;
  for (let i = 0; i < refIds.length; i += CHUNK) {
    const chunk = refIds.slice(i, i + CHUNK);
    const placeholders = chunk.map((_, j) => `$${j + 2}`).join(", ");
    const rows = await query<EmbeddingRow>(
      `SELECT * FROM embeddings WHERE kind = $1 AND ref_id IN (${placeholders})`,
      [kind, ...chunk],
    );
    out.push(...rows.map(toEmbedding));
  }
  return out;
}

/** Everything embedded for a chat — the reindex path re-embeds these rows'
 * stored texts with the current model. */
export async function listAllChatEmbeddings(chatId: string): Promise<StoredEmbedding[]> {
  const rows = await query<EmbeddingRow>("SELECT * FROM embeddings WHERE chat_id = $1", [chatId]);
  return rows.map(toEmbedding);
}

import { invoke } from "@tauri-apps/api/core";

import { logUsage } from "../db/repositories/usageRepo";
import { estimateTokens } from "../prompt/tokenEstimate";
import type { ConnectionConfig } from "./types";

export interface EmbedResult {
  model: string;
  vectors: number[][];
}

/** Embeds a batch of texts via the connection's provider (Gemini/OpenAI;
 * Claude has no embedding API and rejects). Returns the embedding model id
 * plus one vector per text, in input order. `model` overrides the
 * per-provider default (the `embedding_model` setting). */
export async function embedTexts(
  connection: ConnectionConfig,
  texts: string[],
  model?: string | null,
): Promise<EmbedResult> {
  const [usedModel, vectors] = await invoke<[string, number[][]]>("embed_texts", {
    connectionId: connection.id,
    provider: connection.provider,
    baseUrl: connection.baseUrl,
    model: model ?? null,
    texts,
  });
  const inputTokens = texts.reduce((sum, t) => sum + estimateTokens(t), 0);
  void logUsage("embedding", connection.id, inputTokens, 0).catch(() => {});
  return { model: usedModel, vectors };
}

import { execute, query } from "../database";

interface SettingRow {
  key: string;
  value: string;
}

export async function getSetting(key: string): Promise<string | null> {
  const rows = await query<SettingRow>("SELECT key, value FROM settings WHERE key = $1", [key]);
  return rows[0]?.value ?? null;
}

export async function setSetting(key: string, value: string): Promise<void> {
  await execute(
    `INSERT INTO settings (key, value) VALUES ($1, $2)
     ON CONFLICT (key) DO UPDATE SET value = excluded.value`,
    [key, value],
  );
}

export async function resetAllSettings(): Promise<void> {
  await execute("DELETE FROM settings", []);
}

export async function getAllSettings(): Promise<Record<string, string>> {
  const rows = await query<SettingRow>("SELECT key, value FROM settings", []);
  return Object.fromEntries(rows.map((r) => [r.key, r.value]));
}

// ---- Log level (tiered logging) ------------------------------------------

export type LogLevel = "debug" | "info" | "warn" | "error";

const LOG_LEVEL_SETTING_KEY = "log_level";
const LOG_LEVELS: readonly LogLevel[] = ["debug", "info", "warn", "error"];

function isLogLevel(value: string): value is LogLevel {
  return (LOG_LEVELS as readonly string[]).includes(value);
}

/** Reads the configured minimum log level, or `null` if never set (callers
 *  should fall back to the default, `"info"`). */
export async function getLogLevel(): Promise<LogLevel | null> {
  const raw = await getSetting(LOG_LEVEL_SETTING_KEY);
  if (raw && isLogLevel(raw)) return raw;
  return null;
}

/** Persists the configured minimum log level. */
export async function setLogLevel(level: LogLevel): Promise<void> {
  await setSetting(LOG_LEVEL_SETTING_KEY, level);
}

// ---- Calendar helpers (plan M23) ----------------------------------------

export const CALENDAR_SETTING_KEY = "game_calendar";

export interface CalendarJSON {
  year: number;
  dayOfYear: number;
}

/** Reads the stored calendar for a chat, or returns null if never set. */
export async function getCalendarSetting(chatId: string): Promise<CalendarJSON | null> {
  const key = `${CALENDAR_SETTING_KEY}_${chatId}`;
  const raw = await getSetting(key);
  if (!raw) return null;
  try {
    const parsed = JSON.parse(raw) as CalendarJSON;
    if (typeof parsed.year === "number" && typeof parsed.dayOfYear === "number") {
      return parsed;
    }
  } catch {
    // fall through
  }
  return null;
}

/** Persists the calendar JSON for a chat. */
export async function setCalendarSetting(chatId: string, cal: CalendarJSON): Promise<void> {
  const key = `${CALENDAR_SETTING_KEY}_${chatId}`;
  await setSetting(key, JSON.stringify(cal));
}

// ---- Sync helpers (M14) -------------------------------------------------

/** Generates and stores a random device-id the first time sync is enabled.
 *  Returns the existing device-id if one is already stored. */
export async function ensureDeviceId(): Promise<string> {
  const existing = await getSetting("device_id");
  if (existing) return existing;
  const id = crypto.randomUUID();
  await setSetting("device_id", id);
  return id;
}

export interface SyncPosition {
  file: string;
  byteOffset: number;
}

/** Reads tracked sync positions (which byte of each foreign journal file has
 *  already been processed). Returns an empty array when nothing is tracked. */
export async function getSyncPositions(): Promise<SyncPosition[]> {
  const raw = await getSetting("sync_positions");
  if (!raw) return [];
  try {
    const parsed = JSON.parse(raw);
    if (!Array.isArray(parsed)) return [];
    return parsed.filter(
      (p: unknown): p is SyncPosition =>
        typeof p === "object" && p !== null &&
        typeof (p as SyncPosition).file === "string" &&
        typeof (p as SyncPosition).byteOffset === "number",
    );
  } catch {
    return [];
  }
}

/** Persists the current sync positions. */
export async function setSyncPositions(positions: SyncPosition[]): Promise<void> {
  await setSetting("sync_positions", JSON.stringify(positions));
}

/** Pure vector helpers for the semantic memory layer — no DB/Tauri imports
 * so they're unit-testable. Vectors travel through SQLite as base64-encoded
 * little-endian f32 arrays (see migration 002). */

export function encodeVector(vec: number[] | Float32Array): string {
  const f32 = vec instanceof Float32Array ? vec : Float32Array.from(vec);
  const bytes = new Uint8Array(f32.buffer, f32.byteOffset, f32.byteLength);
  let binary = "";
  const CHUNK = 0x8000;
  for (let i = 0; i < bytes.length; i += CHUNK) {
    binary += String.fromCharCode(...bytes.subarray(i, i + CHUNK));
  }
  return btoa(binary);
}

export function decodeVector(b64: string): Float32Array {
  const binary = atob(b64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
  return new Float32Array(bytes.buffer);
}

/** Cosine similarity in [-1, 1]. Returns 0 for a dimension mismatch (e.g.
 * rows embedded by a different model) or a zero vector — such rows just
 * rank at the bottom instead of throwing. */
export function cosineSimilarity(a: Float32Array, b: Float32Array): number {
  if (a.length !== b.length || a.length === 0) return 0;
  let dot = 0;
  let normA = 0;
  let normB = 0;
  for (let i = 0; i < a.length; i++) {
    dot += a[i] * b[i];
    normA += a[i] * a[i];
    normB += b[i] * b[i];
  }
  if (normA === 0 || normB === 0) return 0;
  return dot / (Math.sqrt(normA) * Math.sqrt(normB));
}

